func TestBackupStorageLocationMetric(t *testing.T) {
	err := velerov1api.AddToScheme(scheme.Scheme)
	require.NoError(t, err)

	tests := []struct {
		name           string
		isValidError   error
		expectedStatus int64
		description    string
	}{
		{
			name:           "BSL is valid",
			isValidError:   nil,
			expectedStatus: metrics.BSLLastStatusSucc,
			description:    "should set metric to success when BSL is available",
		},
		{
			name:           "BSL is invalid",
			isValidError:   errors.New("validation failed"),
			expectedStatus: metrics.BSLLastStatusFailure,
			description:    "should set metric to failure when BSL is unavailable",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			// Setup
			bsl := builder.ForBackupStorageLocation("velero", "test-bsl").Result()
			bsl.Spec.Default = true

			client := fake.NewClientBuilder().WithScheme(scheme.Scheme).WithObjects(bsl).Build()

			pluginManager := &pluginmocks.Manager{}
			pluginManager.On("CleanupClients").Return()

			backupStore := &persistencemocks.BackupStore{}
			backupStore.On("IsValid").Return(tc.isValidError)

			backupStoreGetter := &persistencemocks.ObjectBackupStoreGetter{}
			backupStoreGetter.On("Get", bsl, pluginManager, (*logrus.Entry)(nil)).Return(backupStore, nil)

			// Create metrics instance
			serverMetrics := metrics.NewServerMetrics()
			serverMetrics.RegisterAllMetrics()

			reconciler := &backupStorageLocationReconciler{
				ctx:                       context.Background(),
				client:                    client,
				newPluginManager:          func(logrus.FieldLogger) clientmgmt.Manager { return pluginManager },
				backupStoreGetter:         backupStoreGetter,
				metrics:                   serverMetrics,
				defaultBackupLocationInfo: storage.DefaultBackupLocationInfo{},
				log:                       logrus.StandardLogger(),
			}

			// Execute
			_, err := reconciler.Reconcile(context.Background(), ctrl.Request{
				NamespacedName: types.NamespacedName{
					Namespace: "velero",
					Name:      "test-bsl",
				},
			})

			require.NoError(t, err)

			// Verify metric was registered
			metricFamilies, err := prometheus.DefaultGatherer.Gather()
			require.NoError(t, err)

			foundMetric := false
			for _, mf := range metricFamilies {
				if mf.GetName() == "velero_velero_backup_storage_location_last_status" {
					foundMetric = true
					metrics := mf.GetMetric()
					require.NotEmpty(t, metrics)

					metric := metrics[0]
					assert.Equal(t, float64(tc.expectedStatus), metric.GetGauge().GetValue())

					labels := metric.GetLabel()
					assert.Len(t, labels, 2)
					assert.Equal(t, "name", labels[0].GetName())
					assert.Equal(t, "test-bsl", labels[0].GetValue())
					assert.Equal(t, "namespace", labels[1].GetName())
					assert.Equal(t, "velero", labels[1].GetValue())
					break
				}
			}

			assert.True(t, foundMetric, "BSL status metric should be found")
		})
	}
}

