// Test for BSL metric functionality
package controller

import (
	"testing"

	"github.com/stretchr/testify/assert"

	"github.com/vmware-tanzu/velero/pkg/metrics"
)

func TestBackupStorageLocationMetricValues(t *testing.T) {
	tests := []struct {
		name           string
		expectedStatus int64
		description    string
	}{
		{
			name:           "BSL success status",
			expectedStatus: metrics.BSLLastStatusSucc,
			description:    "should have BSL last status success value of 1",
		},
		{
			name:           "BSL failure status",
			expectedStatus: metrics.BSLLastStatusFailure,
			description:    "should have BSL last status failure value of 0",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			// Verify the metric constants are correctly defined
			assert.Equal(t, int64(1), metrics.BSLLastStatusSucc, "BSLLastStatusSucc should be 1")
			assert.Equal(t, int64(0), metrics.BSLLastStatusFailure, "BSLLastStatusFailure should be 0")

			// Test the metric registration function
			serverMetrics := metrics.NewServerMetrics()
			serverMetrics.RegisterAllMetrics()

			// This is a basic test to ensure the metric function can be called without error
			// In a real integration test, we would verify the metric is actually recorded
			serverMetrics.RegisterBackupStorageLocationLastStatus("test-bsl", "velero", tc.expectedStatus)

			t.Logf("Test passed: %s", tc.description)
		})
	}
}
